export interface TacticalPuzzle {
  id: string;
  fen: string;
  solution: string;
  theme: string;
  difficulty: number;
  playerColor: 'white' | 'black';
  instruction: string;
  successMessage: string;
}

// Get today's date as a seed for daily puzzle selection
function getDayOfYear(): number {
  const now = new Date();
  const start = new Date(now.getFullYear(), 0, 0);
  const diff = now.getTime() - start.getTime();
  return Math.floor(diff / (1000 * 60 * 60 * 24));
}

// Seeded random number generator for deterministic daily selection
function seededRandom(seed: number): () => number {
  let s = seed;
  return () => {
    s = (s * 16807 + 0) % 2147483647;
    return (s - 1) / 2147483646;
  };
}

// Get 5 daily puzzles based on the current date
export function getDailyPuzzles(): TacticalPuzzle[] {
  const daySeed = getDayOfYear();
  const rng = seededRandom(daySeed);
  const shuffled = [...ALL_PUZZLES].sort(() => rng() - 0.5);
  return shuffled.slice(0, 5);
}

// Get all puzzles for a specific theme
export function getPuzzlesByTheme(theme: string): TacticalPuzzle[] {
  return ALL_PUZZLES.filter(p => p.theme === theme);
}

// Get theme counts
export function getThemeCounts(): Record<string, number> {
  const counts: Record<string, number> = {};
  ALL_PUZZLES.forEach(p => {
    counts[p.theme] = (counts[p.theme] || 0) + 1;
  });
  return counts;
}



